chrome.runtime.onInstalled.addListener(()=>{console.log("Snipo Open installed")});chrome.commands.onCommand.addListener(s=>{chrome.tabs.query({active:!0,currentWindow:!0},a=>{const e=a[0];if(e!=null&&e.id)switch(s){case"time":chrome.tabs.sendMessage(e.id,{type:"ADD_NOTE"});break;case"screen":chrome.tabs.sendMessage(e.id,{type:"SCREENSHOT"});break;case"pause":chrome.tabs.sendMessage(e.id,{type:"TOGGLE_PLAY"});break;case"back5s":chrome.tabs.sendMessage(e.id,{type:"SEEK",seconds:-5});break;case"skip5s":chrome.tabs.sendMessage(e.id,{type:"SEEK",seconds:5});break;case"speed-inc":chrome.tabs.sendMessage(e.id,{type:"SPEED_INC"});break;case"speed-dec":chrome.tabs.sendMessage(e.id,{type:"SPEED_DEC"});break;case"transcript":chrome.tabs.sendMessage(e.id,{type:"TOGGLE_TRANSCRIPT"});break;case"clip":chrome.tabs.sendMessage(e.id,{type:"CLIP"});break}})});chrome.runtime.onMessage.addListener((s,a,e)=>{s.type==="PLATFORM_DETECTED"&&chrome.storage.local.set({currentVideo:s.payload})});
